import { useRef, useState } from 'react';
import { Camera, Trash2, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { cn } from '@/shadcn/lib/utils';
import { HarmonyAlertDialog } from '@/components/ui/harmony-alert-dialog';

interface HarmonyProfilePictureUploaderProps {
  /** Current image URL to display. Pass null/undefined to show fallback. */
  imageUrl?: string | null;
  /** Called when the user selects a valid file. Parent is responsible for the actual upload. */
  onFileSelected: (file: File) => void;
  /** Optional remove handler. Remove button only shows when this prop is provided and either imageUrl or hasImage is truthy. */
  onRemove?: () => void | Promise<void>;
  /** Explicitly signals that an image exists when imageUrl is null (e.g. when a fallback component renders the image). */
  hasImage?: boolean;
  /** Shows a loading overlay while upload is in progress. */
  uploading?: boolean;
  /** Image container shape. 'circle' for person avatars, 'rounded' for logos. Default: 'rounded'. */
  shape?: 'circle' | 'rounded';
  /** Container size. Default: 'md'. */
  size?: 'sm' | 'md' | 'lg';
  /** Content rendered inside the container when no imageUrl is provided. */
  fallback?: React.ReactNode;
  /** Maximum allowed file size in MB. Default: 5. */
  maxFileSizeMb?: number;
  /** Additional classes for the outermost wrapper div. */
  className?: string;
}

const sizeClasses: Record<NonNullable<HarmonyProfilePictureUploaderProps['size']>, string> = {
  sm: 'w-16 h-16',
  md: 'w-24 h-24',
  lg: 'w-40 h-40',
};

const shapeClasses: Record<NonNullable<HarmonyProfilePictureUploaderProps['shape']>, string> = {
  circle: 'rounded-full',
  rounded: 'rounded-2xl',
};

export function HarmonyProfilePictureUploader({
  imageUrl,
  onFileSelected,
  onRemove,
  hasImage,
  uploading = false,
  shape = 'rounded',
  size = 'md',
  fallback,
  maxFileSizeMb = 5,
  className,
}: HarmonyProfilePictureUploaderProps) {
  const inputRef = useRef<HTMLInputElement>(null);
  const [confirmOpen, setConfirmOpen] = useState(false);
  const [removing, setRemoving] = useState(false);

  const handleConfirmRemove = async () => {
    setRemoving(true);
    try {
      await onRemove?.();
    } finally {
      setRemoving(false);
      setConfirmOpen(false);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    e.target.value = '';
    if (!file) return;

    if (!file.type.startsWith('image/')) {
      toast.error('Only image files are allowed.');
      return;
    }

    if (file.size > maxFileSizeMb * 1024 * 1024) {
      toast.error(`Image must be smaller than ${maxFileSizeMb} MB.`);
      return;
    }

    onFileSelected(file);
  };

  return (
    <div className={cn('relative shrink-0 inline-block', className)}>
      {/* Image container */}
      <div
        className={cn(
          sizeClasses[size],
          shapeClasses[shape],
          'overflow-hidden border border-border bg-muted flex items-center justify-center',
        )}
      >
        {imageUrl ? (
          <img src={imageUrl} alt="" className="w-full h-full object-cover" />
        ) : (
          fallback
        )}

        {/* Upload in-progress overlay */}
        {uploading && (
          <div className="absolute inset-0 bg-card/80 flex items-center justify-center z-20 rounded-[inherit]">
            <Loader2 className="animate-spin text-primary" size={20} />
          </div>
        )}
      </div>

      {/* Upload button */}
      <button
        type="button"
        onClick={() => inputRef.current?.click()}
        disabled={uploading}
        className="absolute -bottom-2 -right-2 p-1.5 bg-card rounded-lg shadow border border-border text-primary hover:bg-muted transition-colors disabled:opacity-50"
        title="Upload image"
      >
        <Camera size={12} />
      </button>

      {/* Remove button — only shown when an image exists and onRemove is provided */}
      {onRemove && (imageUrl || hasImage) && (
        <button
          type="button"
          onClick={() => setConfirmOpen(true)}
          disabled={uploading}
          className="absolute -bottom-2 -left-2 p-1.5 bg-card rounded-lg shadow border border-border text-destructive hover:bg-muted transition-colors disabled:opacity-50"
          title="Remove image"
        >
          <Trash2 size={12} />
        </button>
      )}

      {/* Hidden file input — always images only */}
      <input
        ref={inputRef}
        type="file"
        accept="image/*"
        className="hidden"
        onChange={handleChange}
      />

      <HarmonyAlertDialog
        open={confirmOpen}
        onOpenChange={(open) => { if (!removing) setConfirmOpen(open); }}
        variant="danger"
        title="Remove Profile Picture"
        description="This will permanently remove the profile picture. This action cannot be undone."
        actionLabel="Remove"
        onAction={handleConfirmRemove}
        isActioning={removing}
      />
    </div>
  );
}
